const leads = $input.first().json.data || [];
const toValidate = leads.filter(l => l.email && l.email !== '' && l.email !== 'pending' && l.email.includes('@') && l.emailValid === 'pending').slice(0, 10).map(l => ({leadId: l.id, businessName: l.businessName, email: l.email, website: l.website}));
return {leads: toValidate, count: toValidate.length};

const email = $('Filter Pending Validation').first().json.email;
const domain = email.split('@')[1] || '';
const basicChecks = {hasAtSign: email.includes('@'), hasDot: email.includes('.'), validLength: email.length > 5 && email.length < 254, noSpaces: !email.includes(' '), commonFormat: /^[^@]+@[^@]+\.[^@]+$/.test(email), disposableDomains: ['mailinator.com','tempmail.com','guerrillamail.com','10minutemail.com','yopmail.com'], isDisposable: false};
if (domain) { basicChecks.isDisposable = basicChecks.disposableDomains.includes(domain.toLowerCase()); }
basicChecks.basicValid = basicChecks.hasAtSign && basicChecks.hasDot && basicChecks.validLength && basicChecks.noSpaces && basicChecks.commonFormat && !basicChecks.isDisposable;
return basicChecks;

const allInputs = $input.all();
const neverbounceResult = allInputs.find(i => i.json.result)?.json || {};
const basicResult = allInputs.find(i => i.json.basicValid !== undefined)?.json || {};
const lead = $('Filter Pending Validation').first().json;

let finalResult = 'invalid';
let confidence = 0;
let reason = '';

if (neverbounceResult.result === 'valid') { finalResult = 'valid'; confidence = 90; reason = 'NeverBounce verified'; }
else if (neverbounceResult.result === 'catchall') { finalResult = 'risky'; confidence = 50; reason = 'Catch-all domain'; }
else if (neverbounceResult.result === 'unknown') { finalResult = 'unknown'; confidence = 30; reason = 'Cannot verify'; }
else if (basicResult.basicValid) { finalResult = 'risky'; confidence = 40; reason = 'Basic checks passed only'; }
else { finalResult = 'invalid'; confidence = 10; reason = 'Failed all checks'; }

return {leadId: lead.leadId, businessName: lead.businessName, email: lead.email, result: finalResult, confidence: confidence, reason: reason, validatedAt: new Date().toISOString()};

const result = $input.first().json;
const validLeads = result.result === 'valid' ? [{leadId: result.leadId, email: result.email, status: 'valid'}] : [];
const invalidLeads = result.result === 'invalid' ? [{leadId: result.leadId, email: result.email, reason: result.reason}] : [];
return {valid: validLeads, invalid: invalidLeads, total: 1, nextStep: 'dedup'};
